#!/bin/bash
# AEON PAGER PIPELINE: FM demodulator + POCSAG/FLEX plaintext resolver.

FREQ=$1
if [ -z "$FREQ" ]; then
    FREQ="152480000"
fi

log_gateway() {
    echo "[PAGER] $1" >> gateway.log
    echo "[PAGER] $1" >&2
}

if ! command -v rtl_fm >/dev/null 2>&1; then
    log_gateway "rtl_fm not found; cannot demodulate pager audio"
    exit 1
fi

if ! command -v multimon-ng >/dev/null 2>&1; then
    log_gateway "multimon-ng not found; install it for POCSAG/FLEX plaintext decoding"
    exit 1
fi

if [ ! -x ./target/release/pager-residue-collector ]; then
    log_gateway "pager-residue-collector missing; run cargo build --release --bin pager-residue-collector"
    exit 1
fi

DECODERS="-a POCSAG512 -a POCSAG1200 -a POCSAG2400"
if multimon-ng -a help 2>&1 | grep -qi "FLEX"; then
    DECODERS="$DECODERS -a FLEX"
fi

log_gateway "Starting pager resolver on ${FREQ} Hz with ${DECODERS}"

rtl_fm -f "$FREQ" -M fm -s 22050 -g auto -l 0 - 2>>sdr_bridge.log | \
    multimon-ng -t raw $DECODERS - 2>>sdr_bridge.log | \
    ./target/release/pager-residue-collector
